const body = $input.first().json.body || $input.first().json;
const email = (body.email || '').trim().toLowerCase();
const password = body.password || '';

if (!email || !password) {
  return [{ json: { error: 'Email y contraseña requeridos', status: 400, _skip: true } }];
}

const lookupUrl = `https://optima-nocodb.vhsxer.easypanel.host/api/v2/tables/mkb040wimke95sl/records?where=(Email,eq,${email})&limit=1`;

return [{ json: { email, password, lookupUrl } }];

const creds = $('Extract Credentials').first().json;

if (creds._skip || creds.error) {
  return [{ json: { error: creds.error, status: creds.status || 401 } }];
}

const httpResponse = $input.first().json;
const users = httpResponse.list || [];

if (users.length === 0) {
  return [{ json: { error: 'Credenciales inválidas', status: 401 } }];
}

const u = users[0];

if (u['Password Hash'] !== creds.password) {
  return [{ json: { error: 'Credenciales inválidas', status: 401 } }];
}

if (!u['Is Active']) {
  return [{ json: { error: 'Cuenta desactivada', status: 403 } }];
}

const tokenPayload = {
  email: u['Email'],
  company: u['Company Name'],
  exp: Date.now() + (7 * 24 * 60 * 60 * 1000)
};
const token = Buffer.from(JSON.stringify(tokenPayload)).toString('base64');

return [{
  json: {
    success: true,
    token,
    config: {
      company_name: u['Company Name'] || 'Dashboard',
      logo_url: u['Logo URL'] || '',
      api_base: u['API Base'],
      leads_table: u['Leads Table'],
      call_logs_table: u['Call Logs Table'],
      confirmed_table: u['Confirmed Table'],
      error_logs_table: u['Error Logs Table'],
      xc_token: u['XC Token'],
      vapi_api_key: u['Vapi API Key'],
      vapi_public_key: u['Vapi Public Key'],
      vapi_assistant_id: u['Vapi Assistant ID'],
      vapi_phone_number_id: u['Vapi Phone Number ID'],
      zadarma_key: u['Zadarma Key'],
      zadarma_secret: u['Zadarma Secret'],
      zadarma_from_number: u['Zadarma From Number'],
      openai_api_key: u['OpenAI API Key'],
      n8n_webhook_base: u['N8N Webhook Base'] || ''
    },
    status: 200
  }
}];

const body = $input.first().json.body || $input.first().json;
const token = body.token || '';

if (!token) {
  return [{ json: { error: 'Token requerido', status: 401, _skip: true } }];
}

try {
  const payload = JSON.parse(Buffer.from(token, 'base64').toString('utf8'));
  if (payload.exp && payload.exp < Date.now()) {
    return [{ json: { error: 'Sesión expirada', status: 401, _skip: true } }];
  }
  const lookupUrl = `https://optima-nocodb.vhsxer.easypanel.host/api/v2/tables/mkb040wimke95sl/records?where=(Email,eq,${payload.email})&limit=1`;
  return [{ json: { email: payload.email, lookupUrl, _skip: false } }];
} catch (e) {
  return [{ json: { error: 'Token inválido', status: 401, _skip: true } }];
}

const tokenData = $('Decode Token').first().json;

if (tokenData._skip || tokenData.error) {
  return [{ json: { error: tokenData.error, status: tokenData.status || 401 } }];
}

const httpResponse = $input.first().json;
const users = httpResponse.list || [];

if (users.length === 0 || !users[0]['Is Active']) {
  return [{ json: { error: 'Sesión inválida', status: 401 } }];
}

const u = users[0];

return [{
  json: {
    success: true,
    config: {
      company_name: u['Company Name'] || 'Dashboard',
      logo_url: u['Logo URL'] || '',
      api_base: u['API Base'],
      leads_table: u['Leads Table'],
      call_logs_table: u['Call Logs Table'],
      confirmed_table: u['Confirmed Table'],
      error_logs_table: u['Error Logs Table'],
      xc_token: u['XC Token'],
      vapi_api_key: u['Vapi API Key'],
      vapi_public_key: u['Vapi Public Key'],
      vapi_assistant_id: u['Vapi Assistant ID'],
      vapi_phone_number_id: u['Vapi Phone Number ID'],
      zadarma_key: u['Zadarma Key'],
      zadarma_secret: u['Zadarma Secret'],
      zadarma_from_number: u['Zadarma From Number'],
      openai_api_key: u['OpenAI API Key'],
      n8n_webhook_base: u['N8N Webhook Base'] || ''
    },
    status: 200
  }
}];
